play-state:paused;opacity:.45}.equalizer i:nth-child(2){height:22px;animation-delay:.15s}.equalizer i:nth-child(3){height:12px;animation-delay:.3s}.equalizer i:nth-child(4){height:26px;animation-delay:.45s}.equalizer i:nth-child(5){height:16px;animation-delay:.6s}h1{font-size:34px;margin:20px 0 6px;font-weight:500;text-shadow:0 0 12px rgba(126,239,255,.35);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:570px}h2{font-size:24px;margin:0 0 24px;color:#f14cff;text-shadow:0 0 16px rgba(241,76,255,.6);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:570px}.progress-row{display:grid;grid-template-columns:62px 1fr 62px;align-items:center;gap:18px;color:#33cfff;font-size:18px}.progress{height:5px;background:rgba(89,39,146,.55);box-shadow:0 0 12px rgba(207,54,255,.22)}.progress b{display:block;height:100%;background:linear-gradient(90deg,#22eaff,#d34cff);box-shadow:0 0 14px #d34cff;position:relative;transition:width .18s linear}.progress b:after{content:"";position:absolute;right:-7px;top:-5px;width:15px;height:15px;border-radius:50%;background:#df62ff;box-shadow:0 0 14px #df62ff}.controls{display:flex;gap:26px;margin-top:34px;align-items:center}.hex{min-width:88px;height:62px;font-size:24px;clip-path:polygon(18% 0,82% 0,100% 28%,100% 72%,82% 100%,18% 100%,0 72%,0 28%);border-color:#158bdf}.hex.primary{min-width:102px;height:78px;font-size:42px;color:#ff65f5;border-color:#f04dff;box-shadow:0 0 24px rgba(240,77,255,.42),inset 0 0 18px rgba(240,77,255,.18);animation:primaryPulse 2.2s ease-in-out infinite}.hex.like{color:#ff4ee8;border-color:#a22bda;font-size:34px}.hex.like.active{background:rgba(255,78,232,.18);box-shadow:0 0 26px #ff4ee8,inset 0 0 20px rgba(255,78,232,.24)}.volume-row{display:grid;grid-template-columns:70px 1fr 70px 70px;gap:22px;align-items:center;margin-top:30px;position:relative;z-index:2}.volume-row input{accent-color:#25eaff;width:100%;filter:drop-shadow(0 0 8px #25eaff)}.speaker{border:none;background:transparent;font-size:24px}strong{color:#33cfff;font-size:18px}.slim{width:760px;height:86px;padding:12px 18px;display:flex;align-items:center;gap:18px;animation:fadeScale .28s ease-out}.slim img{width:58px;height:58px;object-fit:cover;border:1px solid #df45ff;box-shadow:0 0 12px #df45ff}.slim div{display:flex;flex-direction:column;min-width:220px;max-width:260px}.slim b{font-size:19px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.slim span{color:#ef4cff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.slim .hex{min-width:64px;height:48px;font-size:18px}.source-menu{width:360px;padding:18px;animation:fadeScale .22s ease-out}.source-menu header{display:flex;justify-content:space-between;color:#48cfff;margin-bottom:14px}.source-menu button{display:flex;justify-content:space-between;width:100%;padding:14px 18px;margin:8px 0;border-color:#9134dc;color:#dff8ff;text-align:left}.source-menu button:first-of-type{color:#ff5df1;box-shadow:inset 0 0 18px rgba(240,77,255,.12)}.orb{width:86px;height:86px;border-radius:50%;border-color:#e04cff;background:radial-gradient(circle,#331044,#050712 62%);box-shadow:0 0 30px #e04cff,inset 0 0 22px rgba(0,238,255,.2);animation:pulse 2.3s infinite}.orb:hover{transform:scale(1.14);box-shadow:0 0 48px #e04cff,inset 0 0 30px rgba(0,238,255,.3)}.orb.paused{animation-play-state:paused;filter:saturate(.6)}.orb span{display:block;width:34px;height:34px;margin:auto;border-radius:50%;background:#25eaff;box-shadow:0 0 24px #25eaff}@keyframes stageIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}@keyframes fadeScale{from{opacity:0;transform:scale(.96)}to{opacity:1;transform:scale(1)}}@keyframes glowBreath{0%,100%{box-shadow:0 0 0 1px rgba(0,229,255,.25) inset,0 0 38px rgba(204,45,255,.32),0 0 22px rgba(0,229,255,.18)}50%{box-shadow:0 0 0 1px rgba(0,229,255,.42) inset,0 0 56px rgba(204,45,255,.52),0 0 34px rgba(0,229,255,.32)}}@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.06)}}@keyframes primaryPulse{0%,100%{filter:drop-shadow(0 0 6px #f04dff)}50%{filter:drop-shadow(0 0 18px #f04dff)}}@keyframes wavePulse{0%,100%{opacity:.75;transform:scaleY(.8)}50%{opacity:1;transform:scaleY(1.12)}}@keyframes scan{0%{transform:translateY(-120%)}100%{transform:translateY(120%)}}@keyframes eq{from{height:6px}to{height:30px}}
</style>
